SELECT e.id, e.name, e.organization_name 
FROM event_service.events e 
WHERE e.status = 1 AND NOT e.is_deleted;

SELECT COUNT(DISTINCT t.id) FILTER (WHERE t.legend_name = 'VIP' AND t.is_checked_in) :: numeric 
       / NULLIF(COUNT(DISTINCT t.id) FILTER (WHERE t.legend_name = 'VIP'), 0) AS vip_sold_ratio
FROM event_service.tickets t;

SELECT COUNT(*) 
FROM seat_service.seat_maps 
WHERE status = 'Draft' AND session_id IS NULL AND NOT is_deleted;

SELECT COUNT(*) AS published_events
FROM event_service.events e
WHERE e.status = 4 AND NOT e.is_deleted;

SELECT COUNT(*) AS empty_seats
FROM seat_service.seats
WHERE NOT is_deleted AND status = 'Available';

SELECT COUNT(*) AS total_tickets
FROM event_service.tickets
WHERE NOT is_deleted;

SELECT COUNT(*) AS banned_users
FROM user_service."Users" u
WHERE u."IsBanned" = TRUE AND NOT u."IsDeleted";

SELECT SUM(o.total_amount) AS total_revenue 
FROM payment_service.orders o 
WHERE o.status = 'Paid' AND NOT o.is_deleted;

SELECT COUNT(*) AS connected_orgs
FROM org_service."Organizations" org
WHERE org."StripeAccountId" IS NOT NULL AND NOT org."IsDeleted";

SELECT COUNT(*) AS checked_in_count
FROM event_service.tickets t
WHERE t.is_checked_in = TRUE AND NOT t.is_deleted;

SELECT COUNT(*) AS published_seat_maps
FROM seat_service.seat_maps
WHERE status = 'Published' AND NOT is_deleted;

SELECT AVG(t.price) AS average_ticket_price 
FROM event_service.tickets t 
WHERE NOT t.is_deleted;
